import React, { useEffect, useRef, useState } from "react";
import styled, { keyframes } from "styled-components";

// ===== Palette =====
const PAPER = "#11385C";          // deep cyan blueprint background
const GRID = "#A6D9FF";           // graph-paper grid color (drawn at 12% opacity)
const STROKE = "#E0F4FF";         // primary draftsman stroke
const TITLE_INK = "#E0F4FF";
const TITLE_SUB = "rgba(224,244,255,0.55)";

// ===== Timings (ms) =====
// Total: ~1.8s of drawing + ~300ms hold + ~450ms fade
const BG_MS = 260;                                  // black → cyan crossfade
const PRIM_COUNT = 6;
const PRIM_DUR = 900;                               // each primitive's draw-in
const PRIM_STAGGER = 130;                           // delay between primitive starts
const PRIM_END = (PRIM_COUNT - 1) * PRIM_STAGGER + PRIM_DUR; // ≈1550ms
const TITLE_DELAY = 650;                            // title starts mid-way
const TITLE_DUR = 700;
const TITLE_TEXT = "PORTFOLIO v2.0";
const SUB_TEXT = "DRG-001 · A1 · SCALE 1:1";
const HOLD_END = PRIM_END + 280;                    // ≈1830ms  → matches "~1.8s"
const FADE_MS = 450;
const TEARDOWN_MS = HOLD_END + FADE_MS + 80;

// ===== Wrap (matches project convention) =====
const Wrap = styled.div`
  position: fixed;
  inset: 0;
  z-index: 9999;
  pointer-events: none;
  background-color: rgba(0, 0, 0, ${({ $bgOff }) => ($bgOff ? 0 : 1)});
  transition: background-color ${({ $bgMs }) => $bgMs}ms ease,
              opacity 450ms ease;
  opacity: ${({ $fade }) => ($fade ? 0 : 1)};
`;

// Inner surface — fades in the cyan paper over the initial black background
const Surface = styled.div`
  position: absolute;
  inset: 0;
  background-color: ${PAPER};
  opacity: 0;
  animation: ${keyframes`
    0%   { opacity: 0; }
    100% { opacity: 1; }
  `} 320ms ease-out 40ms forwards;
  overflow: hidden;
`;

const StyledSvg = styled.svg`
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
`;

// Each primitive uses a stroke-dashoffset animation. The path length is
// communicated via pathLength="1" so we can drive any shape with the same
// keyframes (offset:1 → 0). pathLength is widely supported on SVG2.
const drawIn = keyframes`
  from { stroke-dashoffset: 1; }
  to   { stroke-dashoffset: 0; }
`;

const fadeIn = keyframes`
  from { opacity: 0; }
  to   { opacity: 1; }
`;

const Primitive = styled.g`
  fill: none;
  stroke: ${STROKE};
  stroke-width: ${({ $w }) => $w || 1.4};
  stroke-linecap: round;
  stroke-linejoin: round;
  /* pathLength="1" set on each path so a single dasharray works everywhere */
  & path, & line, & circle, & rect, & polyline {
    stroke-dasharray: 1;
    stroke-dashoffset: 1;
    animation: ${drawIn} ${PRIM_DUR}ms cubic-bezier(0.55, 0.05, 0.4, 0.95)
                 ${({ $i }) => $i * PRIM_STAGGER}ms forwards;
  }
  /* dimension-line labels / arrowheads pop AFTER the stroke completes */
  & .label, & .tick {
    opacity: 0;
    animation: ${fadeIn} 220ms ease-out
                 ${({ $i }) => $i * PRIM_STAGGER + PRIM_DUR - 80}ms forwards;
  }
`;

// ===== Corner title block =====
const TitleBlock = styled.div`
  position: absolute;
  right: clamp(20px, 4vw, 56px);
  bottom: clamp(18px, 3.6vw, 48px);
  color: ${TITLE_INK};
  font-family: "Courier New", "Courier", "SF Mono", "JetBrains Mono", Menlo, monospace;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  text-align: right;
  user-select: none;
`;

const titleType = keyframes`
  from { width: 0; }
  to   { width: ${TITLE_TEXT.length}ch; }
`;

const subType = keyframes`
  from { width: 0; }
  to   { width: ${SUB_TEXT.length}ch; }
`;

const cursorBlink = keyframes`
  0%, 49%   { border-right-color: ${TITLE_INK}; }
  50%, 100% { border-right-color: transparent; }
`;

const TitleLine = styled.div`
  display: inline-block;
  overflow: hidden;
  white-space: nowrap;
  font-weight: 700;
  font-size: clamp(14px, 1.6vw, 22px);
  border-right: 2px solid ${TITLE_INK};
  width: 0;
  animation:
    ${titleType} ${TITLE_DUR}ms steps(${TITLE_TEXT.length}) ${TITLE_DELAY}ms forwards,
    ${cursorBlink} 700ms steps(1) ${TITLE_DELAY}ms infinite;
`;

const SubLine = styled.div`
  display: inline-block;
  overflow: hidden;
  white-space: nowrap;
  color: ${TITLE_SUB};
  font-weight: 500;
  font-size: clamp(9px, 0.95vw, 12px);
  margin-top: 8px;
  letter-spacing: 0.28em;
  width: 0;
  animation:
    ${subType} 520ms steps(${SUB_TEXT.length}) ${TITLE_DELAY + TITLE_DUR + 80}ms forwards;
`;

// ===== The blueprint scene =====
// Viewport is normalized to 1000x600; SVG preserveAspectRatio="xMidYMid meet"
// keeps it centered and proportional across screen sizes.
const BlueprintScene = () => {
  // Geometry — picked to look like a real engineering drawing layout:
  //  · big bordered frame
  //  · main circle (the "part" being detailed)
  //  · concentric inner circle
  //  · diagonal construction axes (X marking center)
  //  · horizontal dimension line below the circle with ticks + label
  //  · vertical dimension line right of the circle with ticks + label
  const CX = 420;
  const CY = 300;
  const R_OUT = 175;
  const R_IN = 95;
  const FRAME = { x: 60, y: 60, w: 880, h: 480 };
  // Horizontal dimension line — measures the circle diameter
  const HDIM_Y = CY + R_OUT + 70;
  const HDIM_X1 = CX - R_OUT;
  const HDIM_X2 = CX + R_OUT;
  // Vertical dimension — to the right of the circle
  const VDIM_X = CX + R_OUT + 90;
  const VDIM_Y1 = CY - R_OUT;
  const VDIM_Y2 = CY + R_OUT;

  return (
    <StyledSvg viewBox="0 0 1000 600" preserveAspectRatio="xMidYMid meet" aria-hidden="true">
      <defs>
        {/* Graph-paper grid: 1mm fine lines on a 5mm major-line backdrop */}
        <pattern id="bpGridMinor" x="0" y="0" width="20" height="20" patternUnits="userSpaceOnUse">
          <path d="M 20 0 L 0 0 0 20" fill="none" stroke={GRID} strokeWidth="0.5" opacity="0.12" />
        </pattern>
        <pattern id="bpGridMajor" x="0" y="0" width="100" height="100" patternUnits="userSpaceOnUse">
          <rect width="100" height="100" fill="url(#bpGridMinor)" />
          <path d="M 100 0 L 0 0 0 100" fill="none" stroke={GRID} strokeWidth="0.9" opacity="0.20" />
        </pattern>
        {/* Arrowhead marker for dimension lines */}
        <marker id="bpArrow" viewBox="0 0 10 10" refX="9" refY="5"
                markerWidth="9" markerHeight="9" orient="auto-start-reverse">
          <path d="M 0 0 L 10 5 L 0 10 z" fill={STROKE} />
        </marker>
      </defs>

      {/* Grid backdrop — always-on (no draw-in), feels like the paper itself */}
      <rect x="0" y="0" width="1000" height="600" fill="url(#bpGridMajor)" />

      {/* 1 — Frame */}
      <Primitive $i={0} $w={1.6}>
        <rect
          x={FRAME.x} y={FRAME.y}
          width={FRAME.w} height={FRAME.h}
          pathLength="1"
        />
      </Primitive>

      {/* 2 — Main circle */}
      <Primitive $i={1} $w={1.8}>
        <circle cx={CX} cy={CY} r={R_OUT} pathLength="1" />
      </Primitive>

      {/* 3 — Inner circle */}
      <Primitive $i={2} $w={1.2}>
        <circle cx={CX} cy={CY} r={R_IN} pathLength="1" />
      </Primitive>

      {/* 4 — Construction axes (diagonal cross marking the part's center) */}
      <Primitive $i={3} $w={0.9}>
        <line
          x1={CX - R_OUT - 30} y1={CY}
          x2={CX + R_OUT + 30} y2={CY}
          pathLength="1"
          strokeDasharray="6 4"
          style={{ strokeDasharray: "1", strokeDashoffset: "1" }}
        />
        <line
          x1={CX} y1={CY - R_OUT - 30}
          x2={CX} y2={CY + R_OUT + 30}
          pathLength="1"
        />
      </Primitive>

      {/* 5 — Horizontal dimension line with arrows + tick label */}
      <Primitive $i={4} $w={1.1}>
        {/* extension lines */}
        <line x1={HDIM_X1} y1={CY + R_OUT + 8} x2={HDIM_X1} y2={HDIM_Y + 12} pathLength="1" />
        <line x1={HDIM_X2} y1={CY + R_OUT + 8} x2={HDIM_X2} y2={HDIM_Y + 12} pathLength="1" />
        {/* main dimension line — arrows on both ends */}
        <line
          x1={HDIM_X1} y1={HDIM_Y}
          x2={HDIM_X2} y2={HDIM_Y}
          pathLength="1"
          markerStart="url(#bpArrow)"
          markerEnd="url(#bpArrow)"
        />
        {/* numeric label */}
        <g className="label">
          <rect
            x={CX - 36} y={HDIM_Y - 14}
            width="72" height="22"
            fill={PAPER}
            stroke="none"
          />
          <text
            x={CX} y={HDIM_Y + 2}
            textAnchor="middle"
            fontFamily='"Courier New", "Courier", monospace'
            fontSize="14"
            fontWeight="700"
            fill={STROKE}
            letterSpacing="2"
          >
            350 mm
          </text>
        </g>
      </Primitive>

      {/* 6 — Vertical dimension line + label */}
      <Primitive $i={5} $w={1.1}>
        {/* extension lines */}
        <line x1={CX + R_OUT + 8} y1={VDIM_Y1} x2={VDIM_X + 12} y2={VDIM_Y1} pathLength="1" />
        <line x1={CX + R_OUT + 8} y1={VDIM_Y2} x2={VDIM_X + 12} y2={VDIM_Y2} pathLength="1" />
        {/* main dimension */}
        <line
          x1={VDIM_X} y1={VDIM_Y1}
          x2={VDIM_X} y2={VDIM_Y2}
          pathLength="1"
          markerStart="url(#bpArrow)"
          markerEnd="url(#bpArrow)"
        />
        {/* numeric label, rotated 90° */}
        <g className="label">
          <rect
            x={VDIM_X - 14} y={CY - 36}
            width="28" height="72"
            fill={PAPER}
            stroke="none"
          />
          <text
            x={VDIM_X} y={CY}
            textAnchor="middle"
            dominantBaseline="middle"
            fontFamily='"Courier New", "Courier", monospace'
            fontSize="14"
            fontWeight="700"
            fill={STROKE}
            letterSpacing="2"
            transform={`rotate(-90 ${VDIM_X} ${CY})`}
          >
            350 mm
          </text>
        </g>
      </Primitive>
    </StyledSvg>
  );
};

// ===== Main component =====
const BlueprintCurtain = ({ onFinish }) => {
  const [bgOff, setBgOff] = useState(false);
  const [fade, setFade] = useState(false);
  const [done, setDone] = useState(false);
  const onFinishRef = useRef(onFinish);
  onFinishRef.current = onFinish;

  useEffect(() => {
    const timers = [];
    // Once the hold ends, clear the underlying black so any page content shows through
    timers.push(setTimeout(() => setBgOff(true), HOLD_END));
    // Then fade the whole curtain
    timers.push(setTimeout(() => setFade(true), HOLD_END + 40));
    // Finally tear down + onFinish
    timers.push(
      setTimeout(() => {
        setDone(true);
        if (onFinishRef.current) onFinishRef.current();
      }, TEARDOWN_MS + 80)
    );
    return () => timers.forEach(clearTimeout);
  }, []);

  if (done) return null;

  return (
    <Wrap $bgOff={bgOff} $bgMs={BG_MS} $fade={fade}>
      <Surface>
        <BlueprintScene />
        <TitleBlock>
          <TitleLine>{TITLE_TEXT}</TitleLine>
          <SubLine>{SUB_TEXT}</SubLine>
        </TitleBlock>
      </Surface>
    </Wrap>
  );
};

export default BlueprintCurtain;
